import React, { useState } from 'react';
import '../Styles/Header.css';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { handleLogout } from '../Pages/Auth/Logout';
import Cookie from 'cookie-universal';


export default function Header() {
  const location= useLocation();
 
  const navigate = useNavigate();
  const cookie = Cookie();

  const [user, setUser] = useState(null);

  useEffect(() => {
    const userData = cookie.get('educational-user');
    if (userData) {
      setUser(JSON.parse(userData));
    }
  }, [location]);

  function logout() {
    handleLogout(navigate);
  }

  return (
    <header className="header">
      <div className="container">
        <div className="logo">
          <h2>المنصة التعليمية</h2>
        </div>
        
        <nav className="nav">
          <Link 
            to="/" 
            className={location.pathname === '/' ? 'active' : ''}
          >
            الرئيسية
          </Link>
          
          <Link 
            to="/courses" 
            className={location.pathname === '/courses' ? 'active' : ''}
          >
            الكورسات
          </Link>
          
          <Link 
            to="/pricing" 
            className={location.pathname === '/pricing' ? 'active' : ''}
          >
            الأسعار
          </Link>
          
          <Link 
            to="/login" 
            className={`login-btn ${location.pathname === '/login' ? 'active' : ''}`}
          >
            تسجيل الدخول
          </Link>
          
          <Link 
            to="/register" 
            className={`register-btn ${location.pathname === '/register' ? 'active' : ''}`}
          >
            إنشاء حساب
          </Link>
        </nav>
      </div>
    </header>
  );
}
